/* ================================================================
 * Transight Design System — 원시 토큰 (Tailwind v4 @theme)
 * 색상은 hex 유지 (Figma 정합성). oklch 변환 안 함.
 * 모든 시맨틱 매핑은 theme.css에서 처리.
 * ================================================================ */

@theme {
  /* ── Cool Grey (16단) — 12/13/14는 다크 표면 (랜딩 dark SoT와 정합) ── */
  --color-cool-grey-white: #ffffff;
  --color-cool-grey-01: #fbfcfe;
  --color-cool-grey-02: #f8f9fd;
  --color-cool-grey-03: #f3f4f8;
  --color-cool-grey-04: #e4e7ee;
  --color-cool-grey-05: #cfd3de;
  --color-cool-grey-06: #969faf;
  --color-cool-grey-07: #6d7588;
  --color-cool-grey-08: #4e566a;
  --color-cool-grey-09: #30384b;
  --color-cool-grey-10: #212a3b;
  --color-cool-grey-11: #131b2d;
  --color-cool-grey-12: #0c0e18;
  --color-cool-grey-13: #0a0c14;
  --color-cool-grey-14: #080808;
  --color-cool-grey-black: #000000;

  /* ── Primary Blue ── */
  --color-primary-blue-1: #155dfc;
  --color-primary-blue-2: #3545d6;
  --color-primary-blue-deep: #0d3796;

  /* ── Primary Skyblue ── */
  --color-primary-skyblue-1: #d4e1ff;
  --color-primary-skyblue-2: #88adff;

  /* ── UI Color: 10색 × 3단계 (text / base / pale) ── */
  --color-ui-text-red: #cf443d;
  --color-ui-red: #ff5148;
  --color-ui-pale-red: #ffe7e5;

  --color-ui-text-orange: #e8872e;
  --color-ui-orange: #ff9d42;
  --color-ui-pale-orange: #fff1e4;

  --color-ui-text-yellow: #dfb00b;
  --color-ui-yellow: #f8c50a;
  --color-ui-pale-yellow: #fef9e6;

  --color-ui-text-olive: #8ead27;
  --color-ui-olive: #b3cf57;
  --color-ui-pale-olive: #f3f7e4;

  --color-ui-text-green: #209d59;
  --color-ui-green: #24c06d;
  --color-ui-pale-green: #eafbf1;

  --color-ui-text-skyblue: #129fe5;
  --color-ui-skyblue: #42a1ff;
  --color-ui-pale-skyblue: #e3f6ff;

  --color-ui-text-blue: #396ad7;
  --color-ui-blue: #286bff;
  --color-ui-pale-blue: #e7efff;

  --color-ui-text-purple: #8951d0;
  --color-ui-purple: #a761ff;
  --color-ui-pale-purple: #f2e5ff;

  --color-ui-text-pink: #bd5dbf;
  --color-ui-pink: #ea6feb;
  --color-ui-pale-pink: #faecfb;

  --color-ui-text-amber: #8c6e2d;
  --color-ui-amber: #c9a45a;
  --color-ui-pale-amber: #faf2dd;

  /* ── Accent (deprecated: --color-ui-amber 사용 권장. 한 사이클 호환 alias) ── */
  --color-accent-amber: var(--color-ui-amber);

  /* ── 그래디언트 (원시 값 — primary-blue/skyblue 토큰 참조로 SoT 일관) ── */
  --image-primary-blue-gradient-1: linear-gradient(
    to right,
    var(--color-primary-blue-1),
    var(--color-primary-blue-2)
  );
  --image-primary-blue-gradient-2: linear-gradient(
    to right,
    var(--color-primary-blue-1),
    var(--color-primary-blue-deep)
  );
  --image-primary-skyblue-gradient-1: linear-gradient(
    to right,
    var(--color-primary-skyblue-1),
    var(--color-primary-skyblue-2)
  );
  --image-ui-sidebar-gradient: linear-gradient(
    to right,
    var(--color-primary-skyblue-1),
    var(--color-primary-skyblue-2)
  );

  /* ── 그림자 (--shadow-* → shadow-* 유틸 자동 생성) ── */
  --shadow-primary: 0 4px 15px 0 #e8ecf4;
  --shadow-search-bar: 0 0 6px 2px rgba(122, 137, 196, 0.2);
  --shadow-input: 0 2px 6px 2px rgba(122, 137, 196, 0.1);
  --shadow-hover: 0 6px 15px 0 rgba(50, 64, 119, 0.5);

  /* ── 브레이크포인트 (Tailwind 기본 오버라이드) ── */
  --breakpoint-md: 1550px;
  --breakpoint-lg: 1660px;
}

/* ────────────────────────────────────────────────────────────
 * 그래디언트 utility — Tailwind v4는 --image-* namespace에서
 * 자동 유틸을 생성하지 않으므로 명시적 @utility 선언이 필요.
 * ──────────────────────────────────────────────────────────── */
@utility bg-primary-blue-gradient-1 {
  background-image: var(--image-primary-blue-gradient-1);
}
@utility bg-primary-blue-gradient-2 {
  background-image: var(--image-primary-blue-gradient-2);
}
@utility bg-primary-skyblue-gradient-1 {
  background-image: var(--image-primary-skyblue-gradient-1);
}
@utility bg-ui-sidebar-gradient {
  background-image: var(--image-ui-sidebar-gradient);
}
